// client/src/pages/ProductDetailPage.jsx
import React from 'react';
import { useParams } from 'react-router-dom';
import './ProductDetailPage.css'; // Create this CSS file

const ProductDetailPage = () => {
    const { id } = useParams(); // Get product ID from URL
    // In a real app, you'd fetch product details using this ID
    const product = {
        id: id,
        name: `Product ${id} Name`, // Placeholder
        price: 499.99,
        category: 'Electronics',
        imageUrl: `https://placehold.co/400x300/cccccc/333333?text=Product+${id}`,
        description: `This is a detailed description for Product ${id}. It features cutting-edge technology, superior performance, and a sleek design. Perfect for modern living.`,
        features: [
            'Feature 1: High Resolution Display',
            'Feature 2: Long Battery Life',
            'Feature 3: Fast Processor',
            'Feature 4: Durable Build Quality'
        ],
        stock: 15
    };

    const handleAddToCart = () => {
        console.log(`Added ${product.name} to cart!`);
        // Implement add to cart logic here
    };

    return (
        <div className="product-detail-page container">
            <div className="product-detail-card card">
                <div className="product-image-container">
                    <img src={product.imageUrl} alt={product.name} className="product-detail-image" />
                </div>
                <div className="product-info">
                    <h1>{product.name}</h1>
                    <p className="product-category">Category: {product.category}</p>
                    <p className="product-description">{product.description}</p>
                    <ul className="product-features">
                        {product.features.map((feature, index) => (
                            <li key={index}>{feature}</li>
                        ))}
                    </ul>
                    <p className="product-price">${product.price.toFixed(2)}</p>
                    <p className="product-stock">In Stock: {product.stock}</p>
                    <button onClick={handleAddToCart} className="btn btn-primary add-to-cart-btn">Add to Cart</button>
                </div>
            </div>
        </div>
    );
};

export default ProductDetailPage;
